const requiredFields = ['item_id', 'source_type', 'source_name', 'title', 'content_text'];
const missingFields = requiredFields.filter((field) => !String($json[field] || '').trim());
if (missingFields.length) {
  throw new Error(`NormalizedTextObject missing required fields: ${missingFields.join(', ')}`);
}

const upstreamScoreScale = $json.score_scale;
if (upstreamScoreScale !== undefined && Number(upstreamScoreScale) !== 100) {
  throw new Error('02_enrich_with_llm requires score_scale=100 before enrichment');
}

const contentText = String($json.content_text || '').trim();
if (contentText.length < 40) {
  throw new Error('content_text is too short for reliable enrichment; expected at least 40 characters');
}

return {
  json: {
    ...$json,
    content_text: contentText,
    existing_tags: Array.isArray($json.tags) ? $json.tags.filter(Boolean) : [],
    score_scale: 100,
    model_profile: 'scoring_default',
    prompt_version: 'scoring_v1',
    rubric_version: 'personal_info_processor_v1'
  }
};

const normalizePrivacyLevel = (value) => {
  const normalized = String(value || 'public').trim().toLowerCase();
  return ['public', 'semi_private', 'private', 'sensitive'].includes(normalized)
    ? normalized
    : 'public';
};

const privacyLevel = normalizePrivacyLevel($json.privacy_level || 'public');
const externalLlmAllowed = $json.external_llm_allowed === undefined
  ? !['private', 'sensitive'].includes(privacyLevel)
  : Boolean($json.external_llm_allowed);

if (externalLlmAllowed !== true || ['private', 'sensitive'].includes(privacyLevel)) {
  throw new Error(`02_enrich_with_llm blocked external LLM for privacy_level=${privacyLevel}`);
}

return {
  json: {
    ...$json,
    privacy_level: privacyLevel,
    external_llm_allowed: externalLlmAllowed
  }
};

const llmBaseUrl = String($env.LLM_BASE_URL || '').trim().replace(/\/+$/, '');
const llmModel = String($env.LLM_MODEL || '').trim();
const llmApiKey = String($env.LLM_API_KEY || '').trim();

if (!llmBaseUrl) {
  throw new Error('LLM_BASE_URL is required for 02_enrich_with_llm');
}
if (!llmModel) {
  throw new Error('LLM_MODEL is required for 02_enrich_with_llm');
}
if (!llmApiKey) {
  throw new Error('LLM_API_KEY is required for 02_enrich_with_llm');
}

const llmProvider = String($env.LLM_PROVIDER || '').trim() || (
  /deepseek/i.test(llmModel)
    ? 'deepseek'
    : /gpt|openai/i.test(llmModel) || /openai/i.test(llmBaseUrl)
      ? 'openai'
      : 'openai-compatible'
);

const systemPrompt = [
  'You are the enrichment layer of AIInformationProcessor.',
  'Return JSON only.',
  'Keep category as a short stable English label.',
  'tags must be an array of concise lowercase strings.',
  'All narrative fields must be written in Simplified Chinese.',
  'Return exactly these top-level keys: category, tags, summary, reason, note_quick_take, note_why_useful, note_key_points, note_claims, note_action_items, ai_score, score_dimensions.',
  'summary must be a concise Chinese summary for audit and search, ideally 80 to 220 Chinese characters.',
  'reason must explain in Chinese why the item is valuable, niche, redundant, or low-value, ideally 40 to 160 Chinese characters.',
  'note_quick_take must be one Chinese sentence used in the section 一句话判断.',
  'note_why_useful must be 1 to 3 Chinese sentences explaining why this matters to the user and to a personal knowledge system.',
  'note_key_points must be an array of 2 to 4 objects.',
  'Each note_key_points item must have keys: heading, bullets.',
  'note_key_points[].heading must be a short Chinese heading.',
  'note_key_points[].bullets must be an array of 1 to 3 concise Chinese bullet strings.',
  'note_claims must be an array of 0 to 3 objects with keys: claim, claim_type, evidence_anchor, system_relation.',
  'claim_type should be a short Chinese label such as 方法论, 经验判断, 事实判断, or 观察.',
  'evidence_anchor should cite the source location in a compact form such as transcript chunk 03.',
  'system_relation should explain in Chinese how the claim connects to the user system, retrieval, scoring, clustering, or workflow decisions.',
  'note_action_items must be an array of 0 to 4 concise Chinese action strings.',
  'Use empty arrays instead of fabricating unsupported claims or action items.',
  'Do not output markdown code fences, explanations, or any extra keys.',
  'summary must be the final summary used by the pipeline, not a copy of upstream_summary.',
  'reason must focus on decision value, not generic praise.',
  'ai_score must be an object with keys: keep_score, notify_score, reference_score, action_score, confidence, decision_hint.',
  'keep_score, notify_score, reference_score, and action_score must be integers between 0 and 100.',
  'confidence must be a number between 0 and 1.',
  'decision_hint must be one of: keep_full, keep_reference, review, skip.',
  'score_dimensions must be an object with keys: personal_relevance, information_density, novelty, actionability, long_term_value, source_quality, penalty.',
  'score_dimensions.personal_relevance must be an integer between 0 and 25.',
  'score_dimensions.information_density must be an integer between 0 and 20.',
  'score_dimensions.novelty must be an integer between 0 and 20.',
  'score_dimensions.actionability must be an integer between 0 and 15.',
  'score_dimensions.long_term_value must be an integer between 0 and 15.',
  'score_dimensions.source_quality must be an integer between 0 and 5.',
  'score_dimensions.penalty must be an integer between -20 and 0.',
  'Do not return a top-level score.',
  'ai_score.keep_score is advisory only; the parser will recompute the canonical keep_score from score_dimensions.',
  'Use content_text as the primary source of truth. upstream_summary is optional context only.',
  'If nearest_match is present, use it to judge novelty and incremental value instead of treating novelty as a free-floating opinion.',
  'High similarity should reduce novelty unless the new item clearly adds new facts, structure, or actionability.',
  'The workflow fixes score_scale at 100 and derives top-level score as keep_score divided by score_scale.'
].join('\n');

const matchedPayload = $json.matched_payload && typeof $json.matched_payload === 'object' ? $json.matched_payload : null;
const nearestMatch = matchedPayload ? {
  matched_score: Number($json.matched_score || 0),
  item_id: String(matchedPayload.item_id || '').trim(),
  title: String(matchedPayload.title || '').trim(),
  category: String(matchedPayload.category || '').trim(),
  summary: String(matchedPayload.summary || '').trim(),
  tags: Array.isArray(matchedPayload.tags) ? matchedPayload.tags : []
} : null;

const userPayload = {
  item_id: $json.item_id,
  source_type: $json.source_type,
  source_name: $json.source_name,
  title: $json.title,
  author: $json.author || '',
  canonical_url: $json.canonical_url || '',
  published_at: $json.published_at || '',
  dedupe_action: $json.dedupe_action || 'full_push',
  existing_tags: $json.existing_tags || [],
  upstream_summary: $json.upstream_summary || '',
  nearest_match: nearestMatch,
  preferred_language: 'zh-CN',
  target_note_shape: {
    style: 'reader-facing knowledge note',
    sections: ['一句话判断', '为什么对我有用', '关键观点', '可沉淀 Claims', '可能的行动项']
  },
  score_scale: 100,
  rubric_version: $json.rubric_version,
  scoring_rubric: {
    personal_relevance: { min: 0, max: 25 },
    information_density: { min: 0, max: 20 },
    novelty: { min: 0, max: 20 },
    actionability: { min: 0, max: 15 },
    long_term_value: { min: 0, max: 15 },
    source_quality: { min: 0, max: 5 },
    penalty: { min: -20, max: 0 }
  },
  content_text: $json.content_text
};

return {
  json: {
    ...$json,
    prompt_version: String($json.prompt_version || 'scoring_v2_cn_note').trim() || 'scoring_v2_cn_note',
    note_view_version: String($json.note_view_version || 'zh_reader_v1').trim() || 'zh_reader_v1',
    llm_base_url: llmBaseUrl,
    llm_model: llmModel,
    llm_provider: llmProvider,
    llm_endpoint: `${llmBaseUrl}/chat/completions`,
    llm_request: {
      model: llmModel,
      temperature: 0.1,
      response_format: {
        type: 'json_object'
      },
      messages: [
        {
          role: 'system',
          content: systemPrompt
        },
        {
          role: 'user',
          content: JSON.stringify(userPayload, null, 2)
        }
      ]
    }
  }
};

const original = $('Build LLM Request').item.json || {};
const rawContent = $json?.choices?.[0]?.message?.content;
if (!rawContent || typeof rawContent !== 'string') {
  throw new Error('LLM response did not include choices[0].message.content');
}

const stripCodeFence = (value) => String(value)
  .trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(stripCodeFence(rawContent));
} catch (error) {
  throw new Error(`Failed to parse LLM JSON response: ${error.message}`);
}

const normalizeMultiline = (value = '') => String(value ?? '')
  .replace(/\r\n/g, '\n')
  .replace(/\u0000/g, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const normalizeSingleLine = (value = '') => normalizeMultiline(value)
  .replace(/\s+/g, ' ')
  .trim();

const extractQuickTake = (value = '') => {
  const normalized = normalizeSingleLine(value);
  if (!normalized) {
    return '';
  }
  const sentenceMatch = normalized.match(/^.{1,140}?[。！？!?](?=\s|$)/);
  if (sentenceMatch?.[0]) {
    return sentenceMatch[0].trim();
  }
  return normalized.length <= 140 ? normalized : `${normalized.slice(0, 137).trim()}...`;
};

const toClampedInt = (value, min, max, fieldName) => {
  const numericValue = Math.round(Number(value));
  if (!Number.isFinite(numericValue)) {
    throw new Error(`LLM response ${fieldName} must be numeric`);
  }
  return Math.max(min, Math.min(max, numericValue));
};

const toClampedFloat = (value, min, max, fieldName) => {
  const numericValue = Number(value);
  if (!Number.isFinite(numericValue)) {
    throw new Error(`LLM response ${fieldName} must be numeric`);
  }
  return Math.max(min, Math.min(max, numericValue));
};

const toStringArray = (value) => {
  if (Array.isArray(value)) {
    return value;
  }
  if (typeof value === 'string') {
    return value.split(/[\n,]+/);
  }
  return [];
};

const normalizeKeyPoints = (value) => {
  const rawItems = Array.isArray(value) ? value : [];
  const normalized = [];

  for (const rawItem of rawItems) {
    if (normalized.length >= 4) {
      break;
    }

    if (typeof rawItem === 'string') {
      const text = normalizeSingleLine(rawItem);
      if (!text) {
        continue;
      }
      normalized.push({
        heading: text.slice(0, 60),
        bullets: [text]
      });
      continue;
    }

    if (!rawItem || typeof rawItem !== 'object') {
      continue;
    }

    const heading = normalizeSingleLine(
      rawItem.heading
      || rawItem.title
      || rawItem.label
      || rawItem.point
      || ''
    ).slice(0, 60);
    const bulletCandidates = Array.isArray(rawItem.bullets)
      ? rawItem.bullets
      : Array.isArray(rawItem.points)
        ? rawItem.points
        : toStringArray(rawItem.bullets || rawItem.summary || rawItem.text || '');
    const bullets = bulletCandidates
      .map((entry) => normalizeSingleLine(entry))
      .filter(Boolean)
      .slice(0, 3);

    if (!heading && !bullets.length) {
      continue;
    }

    normalized.push({
      heading: heading || bullets[0].slice(0, 60),
      bullets: bullets.length ? bullets : [heading]
    });
  }

  return normalized;
};

const normalizeClaims = (value) => {
  const rawItems = Array.isArray(value) ? value : [];
  const normalized = [];

  for (const rawItem of rawItems) {
    if (normalized.length >= 3) {
      break;
    }

    if (typeof rawItem === 'string') {
      const claim = normalizeSingleLine(rawItem);
      if (!claim) {
        continue;
      }
      normalized.push({
        claim,
        claim_type: '',
        evidence_anchor: '',
        system_relation: ''
      });
      continue;
    }

    if (!rawItem || typeof rawItem !== 'object') {
      continue;
    }

    const claim = normalizeSingleLine(rawItem.claim || rawItem.statement || rawItem.summary || '');
    if (!claim) {
      continue;
    }

    normalized.push({
      claim,
      claim_type: normalizeSingleLine(rawItem.claim_type || rawItem.type || ''),
      evidence_anchor: normalizeSingleLine(rawItem.evidence_anchor || rawItem.evidence || rawItem.anchor || ''),
      system_relation: normalizeSingleLine(rawItem.system_relation || rawItem.relation || '')
    });
  }

  return normalized;
};

const normalizeActionItems = (value) => toStringArray(value)
  .map((entry) => normalizeSingleLine(entry))
  .filter(Boolean)
  .slice(0, 4);

const category = normalizeSingleLine(parsed.category || '');
const summary = normalizeMultiline(parsed.summary || '');
const reason = normalizeMultiline(parsed.reason || '');
if (!category) {
  throw new Error('LLM response category must be non-empty');
}
if (!summary) {
  throw new Error('LLM response summary must be non-empty');
}
if (!reason) {
  throw new Error('LLM response reason must be non-empty');
}

const parsedDimensions = parsed.score_dimensions && typeof parsed.score_dimensions === 'object'
  ? parsed.score_dimensions
  : parsed.dimensions && typeof parsed.dimensions === 'object'
    ? parsed.dimensions
    : null;
if (!parsedDimensions) {
  throw new Error('LLM response score_dimensions must be an object');
}

const scoreDimensions = {
  personal_relevance: toClampedInt(parsedDimensions.personal_relevance, 0, 25, 'score_dimensions.personal_relevance'),
  information_density: toClampedInt(parsedDimensions.information_density, 0, 20, 'score_dimensions.information_density'),
  novelty: toClampedInt(parsedDimensions.novelty, 0, 20, 'score_dimensions.novelty'),
  actionability: toClampedInt(parsedDimensions.actionability, 0, 15, 'score_dimensions.actionability'),
  long_term_value: toClampedInt(parsedDimensions.long_term_value, 0, 15, 'score_dimensions.long_term_value'),
  source_quality: toClampedInt(parsedDimensions.source_quality, 0, 5, 'score_dimensions.source_quality'),
  penalty: toClampedInt(parsedDimensions.penalty, -20, 0, 'score_dimensions.penalty')
};

const upstreamScoreScale = Math.round(Number(original.score_scale ?? 100));
if (!Number.isFinite(upstreamScoreScale) || upstreamScoreScale !== 100) {
  throw new Error('02_enrich_with_llm requires score_scale=100 after request preparation');
}
const scoreScale = 100;
const keepScore = Math.max(0, Math.min(scoreScale,
  scoreDimensions.personal_relevance
  + scoreDimensions.information_density
  + scoreDimensions.novelty
  + scoreDimensions.actionability
  + scoreDimensions.long_term_value
  + scoreDimensions.source_quality
  + scoreDimensions.penalty
));

const parsedAiScore = parsed.ai_score && typeof parsed.ai_score === 'object' ? parsed.ai_score : {};
const decisionHint = normalizeSingleLine(parsedAiScore.decision_hint || '') || 'review';
if (!['keep_full', 'keep_reference', 'review', 'skip'].includes(decisionHint)) {
  throw new Error('LLM response ai_score.decision_hint must be one of keep_full, keep_reference, review, skip');
}

const aiScore = {
  keep_score: keepScore,
  notify_score: toClampedInt(parsedAiScore.notify_score ?? keepScore, 0, 100, 'ai_score.notify_score'),
  reference_score: toClampedInt(parsedAiScore.reference_score ?? keepScore, 0, 100, 'ai_score.reference_score'),
  action_score: toClampedInt(parsedAiScore.action_score ?? 0, 0, 100, 'ai_score.action_score'),
  confidence: Number(toClampedFloat(parsedAiScore.confidence ?? 0.7, 0, 1, 'ai_score.confidence').toFixed(4)),
  decision_hint: decisionHint
};

const normalizedScore = Number((keepScore / scoreScale).toFixed(4));
let score = Number.isFinite(Number(original.score))
  ? Number(toClampedFloat(original.score, 0, 1, 'score').toFixed(4))
  : normalizedScore;
if (Math.abs(normalizedScore - score) > 0.001) {
  score = normalizedScore;
}

const normalizedTags = Array.isArray(parsed.tags)
  ? parsed.tags
  : typeof parsed.tags === 'string'
    ? parsed.tags.split(',')
    : [];
const mergedTags = [...new Set([
  ...((Array.isArray(original.existing_tags) ? original.existing_tags : []).map((tag) => String(tag).trim()).filter(Boolean)),
  ...normalizedTags.map((tag) => String(tag).trim().toLowerCase()).filter(Boolean)
])];

const noteQuickTake = normalizeMultiline(parsed.note_quick_take || parsed.quick_take || '');
const noteWhyUseful = normalizeMultiline(parsed.note_why_useful || parsed.why_useful || '');
const noteKeyPoints = normalizeKeyPoints(parsed.note_key_points || parsed.key_points);
const noteClaims = normalizeClaims(parsed.note_claims || parsed.claims);
const noteActionItems = normalizeActionItems(parsed.note_action_items || parsed.action_items);

const quickTake = noteQuickTake || extractQuickTake(summary) || extractQuickTake(reason);
const whyUseful = noteWhyUseful || reason || summary;
const keyPoints = noteKeyPoints.length
  ? noteKeyPoints
  : summary
    ? [{ heading: '内容概览', bullets: [normalizeSingleLine(summary)] }]
    : [];

const scoredAt = new Date().toISOString();
const aiMeta = {
  model_profile: String(original.model_profile || 'scoring_default'),
  provider: String(original.llm_provider || 'openai-compatible'),
  model: String(original.llm_model || '').trim(),
  prompt_version: String(original.prompt_version || 'scoring_v2_cn_note'),
  rubric_version: String(original.rubric_version || 'personal_info_processor_v1'),
  input_chars: String(original.content_text || '').length,
  scored_at: scoredAt
};

return {
  json: {
    ...original,
    score,
    score_scale: scoreScale,
    category,
    tags: mergedTags,
    summary,
    reason,
    note_view_version: String(original.note_view_version || 'zh_reader_v1').trim() || 'zh_reader_v1',
    note_quick_take: quickTake,
    note_why_useful: whyUseful,
    note_key_points: keyPoints,
    note_claims: noteClaims,
    note_action_items: noteActionItems,
    ai_score: aiScore,
    score_dimensions: scoreDimensions,
    ai_meta: aiMeta,
    enriched_at: scoredAt,
    status: 'enriched'
  }
};
